// ─── 9C Audit: Lexer ────────────────────────────────────────────────────────

#[test]
fn lex_breakthrough_identifier() {
    let kinds = tokenize("breakthrough");
    assert!(matches!(&kinds[0], TokenKind::Ident(s) if s == "breakthrough"));
}

#[test]
