    // via mutable counter side-effects if we had them; instead just confirm result is correct
    let interp = run("let s = join([\"x\", \"y\"], \"-\")").unwrap();
    assert_eq!(interp.get_var("s").unwrap(), Value::Str("x-y".to_string()));
