#[test]
fn bytecode_has_key_emits_has_key() {
    let prog = compile_prog("let m = {\"a\": 1}\nlet b = has_key(m, \"a\")");
    let has = prog
        .main
        .instructions
        .iter()
        .any(|i| matches!(i, Instruction::HasKey));
    assert!(has, "expected HasKey instruction");
}

