fn fn_remove_local_mutable_map() {
    let prog = "fn drain() -> Number {\n  let mut m = {\"a\": 1, \"b\": 2}\n  let total = remove(m, \"a\") + remove(m, \"b\")\n  return total\n}\nprint(drain())";
    assert_eq!(vm_run(prog).unwrap(), vec!["3"]);
}

