#[test]
fn interp_for_each_indexed_basic_index() {
    let out = vm_run(
        "let a = [10, 20, 30]\nlet mut sum: Number = 0\nfor i, v in a { sum += i }\nprint(sum)",
    );
    // i = 0 + 1 + 2 = 3
    assert_eq!(out.unwrap(), vec!["3"]);
}

