#[test]
fn type_assign_empty_map_without_context_error() {
    let result = check("let mut m: Map<Text, Number> = {}\nm = {}");
    // Both empty maps — first needs annotation (ok), second needs context (ok via Assign path)
    assert!(result.is_ok());
}

