// --- Parser tests ---

#[test]
fn parse_field_assign_number() {
    let src = r#"
        struct S { x: Number }
        let mut s = S { x: 1 }
        s.x = 42
    "#;
    let tokens = Lexer::new(src).tokenize().unwrap();
    let stmts = Parser::new(tokens).parse().unwrap();
    assert!(stmts.len() == 3);
    // s.x = 42 → TargetAssign { target: Field(Var("s"), "x") }
    if let crate::ast::Stmt::TargetAssign { target, .. } = &stmts[2] {
        if let crate::ast::AssignTarget::Field(inner, field) = target {
            assert!(matches!(inner.as_ref(), crate::ast::AssignTarget::Var(n) if n == "s"));
            assert_eq!(field, "x");
        } else {
            panic!("expected Field target");
        }
    } else {
        panic!("expected TargetAssign");
    }
}

#[test]
fn parse_field_assign_text() {
    let src = r#"
        struct S { name: Text }
        let mut s = S { name: "a" }
        s.name = "bob"
    "#;
    let tokens = Lexer::new(src).tokenize().unwrap();
    let stmts = Parser::new(tokens).parse().unwrap();
    if let crate::ast::Stmt::TargetAssign { target, .. } = &stmts[2] {
        if let crate::ast::AssignTarget::Field(inner, field) = target {
            assert!(matches!(inner.as_ref(), crate::ast::AssignTarget::Var(n) if n == "s"));
            assert_eq!(field, "name");
        } else {
            panic!("expected Field target");
        }
    } else {
        panic!("expected TargetAssign");
    }
}

#[test]
fn parse_field_compound_add() {
    let src = r#"
        struct S { x: Number }
        let mut s = S { x: 1 }
        s.x += 5
    "#;
    let tokens = Lexer::new(src).tokenize().unwrap();
    let stmts = Parser::new(tokens).parse().unwrap();
    if let crate::ast::Stmt::TargetCompoundAssign { target, op, .. } = &stmts[2] {
        assert!(matches!(op, crate::ast::CompoundAssignOp::Add));
        if let crate::ast::AssignTarget::Field(inner, field) = target {
            assert!(matches!(inner.as_ref(), crate::ast::AssignTarget::Var(n) if n == "s"));
            assert_eq!(field, "x");
        } else {
            panic!("expected Field target");
        }
    } else {
        panic!("expected TargetCompoundAssign");
    }
}

#[test]
fn parse_field_compound_subtract() {
    let src = r#"
        struct S { x: Number }
        let mut s = S { x: 10 }
        s.x -= 3
    "#;
    let tokens = Lexer::new(src).tokenize().unwrap();
    let stmts = Parser::new(tokens).parse().unwrap();
    assert!(matches!(
        &stmts[2],
        crate::ast::Stmt::TargetCompoundAssign {
            op: crate::ast::CompoundAssignOp::Subtract,
            ..
        }
    ));
}

#[test]
fn parse_field_compound_multiply() {
    let src = r#"
        struct S { x: Number }
        let mut s = S { x: 3 }
        s.x *= 4
    "#;
    let tokens = Lexer::new(src).tokenize().unwrap();
    let stmts = Parser::new(tokens).parse().unwrap();
    assert!(matches!(
        &stmts[2],
        crate::ast::Stmt::TargetCompoundAssign {
            op: crate::ast::CompoundAssignOp::Multiply,
            ..
        }
    ));
}

#[test]
fn parse_field_compound_divide() {
    let src = r#"
        struct S { x: Number }
        let mut s = S { x: 10 }
        s.x /= 2
    "#;
    let tokens = Lexer::new(src).tokenize().unwrap();
    let stmts = Parser::new(tokens).parse().unwrap();
    assert!(matches!(
        &stmts[2],
        crate::ast::Stmt::TargetCompoundAssign {
            op: crate::ast::CompoundAssignOp::Divide,
            ..
        }
    ));
}

