// --- Bytecode / compiler tests ---

#[test]
fn bytecode_field_assign_emits_set_field() {
    let prog = compile_prog(
        r#"
        struct S { x: Number }
        let mut s = S { x: 1 }
        s.x = 42
    "#,
    );
    let has = prog.main.instructions.iter().any(|i| {
        matches!(i, Instruction::SetPath { root, steps }
            if root == "s"
                && matches!(steps.as_slice(), [crate::ast::PathStep::Field(f)] if f == "x"))
    });
    assert!(has, "expected SET_PATH s.x instruction");
}

#[test]
fn bytecode_field_assign_compiles_rhs_only() {
    let prog = compile_prog(
        r#"
        struct S { x: Number }
        let mut s = S { x: 1 }
        s.x = 42
    "#,
    );
    let has_set_path = prog
        .main
        .instructions
        .iter()
        .any(|i| matches!(i, Instruction::SetPath { .. }));
    let has_field_access = prog
        .main
        .instructions
        .iter()
        .any(|i| matches!(i, Instruction::FieldAccess(_)));
    assert!(has_set_path);
    assert!(
        !has_field_access,
        "SET_PATH should not emit a FIELD_ACCESS read"
    );
}

#[test]
fn bytecode_field_compound_emits_field_compound() {
    let prog = compile_prog(
        r#"
        struct S { x: Number }
        let mut s = S { x: 1 }
        s.x += 5
    "#,
    );
    let has = prog.main.instructions.iter().any(|i| {
        matches!(i, Instruction::PathCompoundAssign { root, steps, op }
            if root == "s"
                && matches!(steps.as_slice(), [crate::ast::PathStep::Field(f)] if f == "x")
                && matches!(op, crate::ast::CompoundAssignOp::Add))
    });
    assert!(has, "expected PATH_COMPOUND_ASSIGN s.x +=");
}

#[test]
fn bytecode_field_compound_compiles_rhs_only() {
    let prog = compile_prog(
        r#"
        struct S { x: Number }
        let mut s = S { x: 1 }
        s.x += 5
    "#,
    );
    let has = prog
        .main
        .instructions
        .iter()
        .any(|i| matches!(i, Instruction::PathCompoundAssign { .. }));
    let has_field_access = prog
        .main
        .instructions
        .iter()
        .any(|i| matches!(i, Instruction::FieldAccess(_)));
    assert!(has);
    assert!(
        !has_field_access,
        "PATH_COMPOUND_ASSIGN should not emit a FIELD_ACCESS read"
    );
}

#[test]
fn bytecode_field_assign_inside_function() {
    let prog = compile_prog(
        r#"
        struct S { x: Number }
        fn update(s_arg: S) {
        }
        let mut s = S { x: 1 }
        s.x = 9
    "#,
    );
    let has = prog
        .main
        .instructions
        .iter()
        .any(|i| matches!(i, Instruction::SetPath { .. }));
    assert!(has);
}

#[test]
fn bytecode_struct_literal_field_access_unchanged_after_field_mutation() {
    let prog = compile_prog(
        r#"
        struct S { x: Number }
        let s = S { x: 1 }
        let v = s.x
        let mut t = S { x: 2 }
        t.x = 3
    "#,
    );
    // FieldAccess should appear (for `s.x` read), SetPath for `t.x = 3`.
    let has_fa = prog
        .main
        .instructions
        .iter()
        .any(|i| matches!(i, Instruction::FieldAccess(_)));
    let has_sp = prog
        .main
        .instructions
        .iter()
        .any(|i| matches!(i, Instruction::SetPath { .. }));
    assert!(has_fa);
    assert!(has_sp);
}

#[test]
fn disassemble_set_field_stable() {
    let prog = compile_prog(
        r#"
        struct S { x: Number }
        let mut s = S { x: 1 }
        s.x = 42
    "#,
    );
    let out = crate::disassemble::disassemble(&prog);
    assert!(out.contains("SET_PATH s.x"), "disassembly: {}", out);
}

#[test]
fn disassemble_field_compound_stable() {
    let prog = compile_prog(
        r#"
        struct S { x: Number }
        let mut s = S { x: 1 }
        s.x += 5
    "#,
    );
    let out = crate::disassemble::disassemble(&prog);
    assert!(
        out.contains("PATH_COMPOUND_ASSIGN s.x +="),
        "disassembly: {}",
        out
    );
}

