// --- Interaction with loops and simulate ---

#[test]
fn method_call_inside_while() {
    let out = vm_run(
        r#"
        struct S { x: Number }
        impl S { fn get(self) -> Number { return self.x } }
        let s = S { x: 5 }
        let mut total = 0
        let mut i = 0
        while i < 3 {
            total += s.get()
            i += 1
        }
        print(total)
    "#,
    )
    .unwrap();
    assert_eq!(out, vec!["15"]);
}

#[test]
