#[test]
fn to_bool_inside_indexed_for_each() {
    let out = vm_run(
        r#"
        let mut count: Number = 0
        for i, s in ["true", "false", "true"] {
            if to_bool(s) { count += i + 1 }
        }
        print(count)
    "#,
    )
    .unwrap();
    // i=0 (true): count += 1; i=1 (false): skip; i=2 (true): count += 3 → total=4
    assert_eq!(out, vec!["4"]);
}

