fn vm_clamp_pops_hi_lo_n_correctly() {
    // If order wrong, clamping would use wrong values
    let out = vm_run("print(clamp(15, 0, 10))\nprint(clamp(-5, 0, 10))").unwrap();
    assert_eq!(out, vec!["10", "0"]);
}

