// --- Loop and simulate interaction ---

#[test]
fn clamp_inside_while() {
    let out = vm_run(
        r#"
        let mut total: Number = 0
        let mut i = 0
        while i < 3 {
            total += clamp(i * 10, 0, 10)
            i += 1
        }
        print(total)
    "#,
    )
    .unwrap();
    // i=0: clamp(0,0,10)=0; i=1: clamp(10,0,10)=10; i=2: clamp(20,0,10)=10 → 20
    assert_eq!(out, vec!["20"]);
}

