// --- Loop and simulate interaction ---

#[test]
fn tau_inside_while() {
    let out = vm_run(
        r#"
        let mut total: Number = 0
        let mut i = 0
        while i < 2 {
            total += round(cos(TAU))
            i += 1
        }
        print(total)
    "#,
    )
    .unwrap();
    assert_eq!(out, vec!["2"]);
}

#[test]
fn tau_inside_for_range() {
    let out = vm_run(
        r#"
        let mut total: Number = 0
        for i in range(0, 2) {
            total += round(sin(TAU))
        }
        print(total)
    "#,
    )
    .unwrap();
    assert_eq!(out, vec!["0"]);
}

#[test]
fn tau_inside_for_each() {
    let out = vm_run(
        r#"
        let angles = [0, TAU]
        let mut total: Number = 0
        for a in angles {
            total += round(cos(a))
        }
        print(total)
    "#,
    )
    .unwrap();
    assert_eq!(out, vec!["2"]);
}

#[test]
fn tau_inside_indexed_for_each() {
    let out = vm_run(
        r#"
        let angles = [PI, TAU]
        let mut total: Number = 0
        for i, a in angles {
            total += round(cos(a))
        }
        print(total)
    "#,
    )
    .unwrap();
    // cos(PI)=-1, cos(TAU)=1 → total=0
    assert_eq!(out, vec!["0"]);
}

